class Solution:
    def getSmallestString(self, n, k):
        result = []
        remaining = k
        for i in range(n):
            positions_left = n - 1 - i
            letter_value = max(1, remaining - 26 * positions_left)
            result.append(chr(ord('a') + letter_value - 1))
            remaining -= letter_value
        return ''.join(result)

