class Solution:
    def getSmallestString(self, n, k):
        letters = ['a'] * n
        remaining = k - n
        i = n - 1
        while remaining > 0 and i >= 0:
            add = min(25, remaining)
            letters[i] = chr(ord('a') + add)
            remaining -= add
            i -= 1
        return ''.join(letters)

