var getSmallestString = function(n, k) {
    const letters = new Array(n).fill('a');
    let remaining = k - n;
    let i = n - 1;
    while (remaining > 0 && i >= 0) {
        const add = Math.min(25, remaining);
        letters[i] = String.fromCharCode('a'.charCodeAt(0) + add);
        remaining -= add;
        i -= 1;
    }
    return letters.join('');
};
